  ('locality-1fb53453-moex-00030', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬法規之制定或發布時無信賴保護原則適用之情形？ 經廢止或變更之法規有重大明顯違反上位規範情形者 相關法規係因主張權益受害者提供不正確資料而發布 純屬法規適用對象主觀之願望而未有表現已生信賴之事實者 相關法規之訂定並未有法律之明確授權 30840、31140 31940 50430', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00031', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '法律為防止盤商囤積雞蛋，以平抑蛋價及滿足民生需求，對違法囤積者每一盒處罰新臺幣 2,500 元，某盤商經主管機關查獲囤積大量雞蛋而被裁處上億元罰鍰，依司法院大法官解釋意旨，此種 裁罰結果最可能牴觸比例原則之何項子原則？ 正當立法目的  適當性原則  必要性原則  狹義比例原則', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00032', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '有關公用地役關係之敘述，下列何者正確？ 公用地役關係因行政機關所為之行政處分而創設 具公用地役關係之現有巷道，於喪失其原有功能或已無繼續供公眾通行之必要時，公用地役關 係自動消滅 土地成立公用地役關係之所有權人對於國家有土地使用費之請求權 行政機關廢止公用地役關係，其性質屬一般處分', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00033', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '有關行政組織之敘述，下列何者正確？ 獨立機關為依據公法設立而具有公法上權利能力者 中央選舉委員會為合議制機關 中小學校家長會屬於學校之行政組織 金融監督管理委員會為獨立機關', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00034', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '下列何者非屬地方制度法所稱之委辦事項？ 內政部將有關外國人入出國、停留、居留、永久居留、收容管理及驅逐出國等業務，委由各直 轄市、縣（市）政府辦理 宜蘭縣政府將核發土地使用分區證明書之權限，委由其轄區內鄉鎮市公所辦理 臺北市政府將部分涉及捷運管理之業務交由新北市政府辦理 內政部將土地徵收補償費、遷移費的查估委由各直轄市或縣（市）政府辦理', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00035', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '法律規定「本法所稱主管機關：在中央為內政部」，下列敘述何者錯誤？ 該法條可作為定管轄競合之依據 該法條不得作為行政機關限制人民基本權利之依據 該法條為事務管轄之依據 該法條屬於組織法規定', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00036', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '依公務員懲戒法規定，下列敘述何者正確？ 受降級處分者，自改敘之日起，4年內不得晉敘、陞任或遷調主管職務 申誡處分，得以口頭方式為之，受申誡人請求，方須作成書面 罰款之懲戒處分不得與剝奪、減少退休（職、伍）金之懲戒處分併為處分 剝奪、減少退休（職、伍）金之懲戒處分，得對現任公務員將來之退休（職、伍）金扣減之', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00037', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '甲任職於某縣政府教育處體育保健科之薦任6職等科員，經同縣府農業處借調到自然生態保育科 擔任薦任6職等科員並占其職缺，甲不服其借調，應依下列何種管道尋求救濟？ 申訴、再申訴程序  訴願程序  復審程序  復查程序', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00038', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '有關公務人員權利義務之敘述，下列何者錯誤？ 甲為公立學校校長，有公務員服務法之適用 乙為縣長之機要秘書，亦受公務人員任用法之保障，縣長對其機要職務不可隨時將其免職 丙公務人員在職死亡者，其遺族丁可向丙之服務機關申辦撫卹 戊為現職軍人，不得參加公務人員協會', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00039', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '衛生福利部就違反食品安全衛生管理法事件之裁罰，訂定「食品安全衛生管理法第四十七條第八 款及第十款標示違規罰鍰處理原則」，此處理原則性質屬於下列何者？ 一般處分  法規命令  行政規則  行政指導 30840、31140 31940 50430', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL)
